struct SegmentTree {
    tree: Vec<i64>,
    base: usize,
}

impl SegmentTree {
    fn new(n: usize) -> Self {
        let mut base = 1;
        while base < n {
            base <<= 1;
        }
        let tree = vec![i64::MIN; 2 * base];
        SegmentTree { tree, base }
    }

    fn update(&mut self, index: usize, value: i64) {
        let mut idx = self.base + index;
        self.tree[idx] = value;
        while idx > 1 {
            idx >>= 1;
            self.tree[idx] = self.tree[2*idx].max(self.tree[2*idx+1]);
        }
    }

    fn query(&self, mut l: usize, mut r: usize) -> i64 {
        if l > r {
            return i64::MIN;
        }
        l += self.base;
        r += self.base;
        let mut res = i64::MIN;
        while l <= r {
            if (l & 1) == 1 {
                res = res.max(self.tree[l]);
                l += 1;
            }
            if (r & 1) == 0 {
                res = res.max(self.tree[r]);
                r = r.checked_sub(1).unwrap();
            }
            l >>= 1;
            r >>= 1;
        }
        res
    }
}

fn solve(weight: Vec<i64>) -> i64 {
    let n = weight.len();
    if n <= 1 {
        return 0;
    }
    let mut prev_greater = vec![None; n];
    let mut stack = Vec::new();

    for i in 0..n {
        while let Some(&j) = stack.last() {
            if weight[j] <= weight[i] {
                stack.pop();
            } else {
                break;
            }
        }
        if let Some(&top) = stack.last() {
            prev_greater[i] = Some(top);
        }
        stack.push(i);
    }

    let mut seg_tree = SegmentTree::new(n);
    let mut dp = vec![0; n];
    dp[0] = 0;
    seg_tree.update(0, dp[0]);

    for i in 1..n {
        let mut candidate_skip = dp[i-1];
        if let Some(L_index) = prev_greater[i] {
            let query_end = if L_index > 0 { L_index - 1 } else { 0 };
            let mut base_value = i64::MIN;
            if L_index == 0 {
                base_value = 0;
            } else {
                let q = seg_tree.query(0, L_index-1);
                base_value = q.max(0);
            }
            let candidate_include = base_value + 1;
            dp[i] = candidate_skip.max(candidate_include);
        } else {
            dp[i] = candidate_skip;
        }
        seg_tree.update(i, dp[i]);
    }
    dp[n-1]
}
```

